

CREATE TABLE buildings (
    id SERIAL PRIMARY KEY,
    geom geometry(MultiPolygon, 4326),
    building VARCHAR(255),
    name VARCHAR(255),
    addr_housenumber VARCHAR(255),
    addr_street VARCHAR(255),
    addr_city VARCHAR(255),
    addr_district VARCHAR(255),
    addr_place VARCHAR(255),
    building_levels VARCHAR(50),
    osm_id VARCHAR(255),
    osm_type VARCHAR(50)
);

CREATE INDEX idx_buildings_geom ON buildings USING GIST (geom);

CREATE TABLE roads (
    id SERIAL PRIMARY KEY,
    geom geometry(MultiLineString, 4326),
    highway VARCHAR(255),
    name VARCHAR(255),
    lanes VARCHAR(50),
    oneway VARCHAR(50),
    surface VARCHAR(255),
    osm_id VARCHAR(255),
    osm_type VARCHAR(50)
);

CREATE INDEX idx_roads_geom ON roads USING GIST (geom);

CREATE TABLE poi (
    id SERIAL PRIMARY KEY,
    geom geometry(MultiPoint, 4326),
    name VARCHAR(255),
    highway VARCHAR(255),
    barrier VARCHAR(255),
    bus VARCHAR(50),
    public_transport VARCHAR(50),
    shelter VARCHAR(50),
    bench VARCHAR(50),
    tactile_paving VARCHAR(50),
    osm_id VARCHAR(255),
    osm_type VARCHAR(50)
);

CREATE INDEX idx_poi_geom ON poi USING GIST (geom);

